package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;
import java.lang.reflect.Method;

class TypeAdapterFromJsonTest {

  private TypeAdapter<String> typeAdapter;

  @BeforeEach
  void setUp() {
    typeAdapter = new TypeAdapter<String>() {
      @Override
      public void write(com.google.gson.stream.JsonWriter out, String value) {
        // no-op for test
      }

      @Override
      public String read(JsonReader in) {
        try {
          // Simulate reading a JSON string literal
          if (in.peek() == JsonToken.STRING) {
            return in.nextString();
          }
          return null;
        } catch (IOException e) {
          return null;
        }
      }
    };
  }

  @Test
  void fromJson_withValidJsonString_returnsExpectedValue() throws IOException {
    String json = "\"hello\"";
    String result = typeAdapter.fromJson(json);
    assertEquals("hello", result);
  }

  @Test
  void fromJson_withEmptyJsonString_returnsNull() throws IOException {
    String json = "null";
    String result = typeAdapter.fromJson(json);
    assertNull(result);
  }

  @Test
  void fromJson_withInvalidJson_throwsIOException() {
    String json = "{invalid json}";
    assertThrows(IOException.class, () -> {
      // Use a spy to throw IOException when read is called
      TypeAdapter<String> spyAdapter = spy(typeAdapter);
      doThrow(new IOException("mock io exception")).when(spyAdapter).read(any());
      spyAdapter.fromJson(json);
    });
  }

  @Test
  void fromJson_invokesPrivateFromJsonReaderMethod() throws Exception {
    String json = "\"test\"";
    Method fromJsonReaderMethod = TypeAdapter.class.getDeclaredMethod("fromJson", Reader.class);
    fromJsonReaderMethod.setAccessible(true);
    String result = (String) fromJsonReaderMethod.invoke(typeAdapter, new StringReader(json));
    assertEquals("test", result);
  }
}
